{
  "query": "query HSN($hsn: String, $product: String) { validateHsn(hsnCode: $hsn, productName: $product) { status hsnCode description gstRatePercent tallyFormat tallyCompatible sourceUrl } }",
  "variables": {
    "hsn": "85287200",
    "product": null
  }
}

{
  "query": "query Rate($q: String!) { forexRate(quoteCurrency: $q) { rate fetchedAt cacheHit } }",
  "variables": { "q": "USD" }
}

{
  "query": "mutation Export($grnId: ID!) { generateTallyExport(kind: GRN, grnId: $grnId) { s3Key presignedUrl exportedAt xmlSize } }",
  "variables": { "grnId": "<grn-uuid>" }
}

{
  "query": "mutation Export($dcId: ID!, $type: String!) { generateTallyExport(kind: DC, dcId: $dcId, voucherType: $type) { s3Key presignedUrl } }",
  "variables": { "dcId": "<dc-uuid>", "type": "Sales" }
}

{
  "query": "mutation Parse($bucket: String!, $key: String!, $boqId: ID) { parseBoq(s3Bucket: $bucket, s3Key: $key, boqUploadId: $boqId) { totalLines matched unmatched hsnWarnings lineItems { description quantity matchedProductId matchConfidence warnings } } }",
  "variables": {
    "bucket": "<private-bucket>",
    "key": "boq-uploads/test-boq.xlsx",
    "boqId": null
  }
}

{
  "query": "mutation Sched($id: ID!) { scheduleInvoiceReminders(action: CREATE, invoiceId: $id) { scheduled deleted stages } }",
  "variables": { "id": "<invoice-uuid>" }
}

{
  "query": "mutation Sched($id: ID!) { scheduleInvoiceReminders(action: CANCEL, invoiceId: $id) { scheduled deleted } }",
  "variables": { "id": "<invoice-uuid>" }
}

{
  "query": "mutation Chat($userId: ID!, $msg: String!) { chatbotMessage(userId: $userId, message: $msg) { sessionId reply sourceCitations { url domain } rateLimited } }",
  "variables": { "userId": "<user-id>", "msg": "How many LG 55UR640S displays are in General Stock?" }
}

{
  "query": "query Alerts { listStockAlertsByIsActive(isActive: \"TRUE\", sortDirection: DESC, limit: 50) { items { id alertType severity message generatedAt productId unitId } } }"
}
